#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <inttypes.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        unsigned long long *A = (unsigned long long*)malloc(sizeof(unsigned long long) * n);
        for (int i = 0; i < n; ++i) {
            scanf("%" SCNu64, &A[i]);
        }
        if (n > 130) {
            printf("Yes\n");
            free(A);
            continue;
        }
        // map xor value -> encoded pair (i<<16 | j) (i<j, both <130 fits in 16 bits)
        // simple open addressing hash table
        const int SZ = 20000; // enough for all pairs
        unsigned long long *key = (unsigned long long*)calloc(SZ, sizeof(unsigned long long));
        unsigned int *val = (unsigned int*)calloc(SZ, sizeof(unsigned int));
        int found = 0;
        for (int i = 0; i < n && !found; ++i) {
            for (int j = i + 1; j < n && !found; ++j) {
                unsigned long long x = A[i] ^ A[j];
                // hash
                unsigned int h = (unsigned int)(x % SZ);
                while (key[h]) {
                    if (key[h] == x) {
                        unsigned int stored = val[h];
                        int p = stored >> 16;
                        int q = stored & 0xFFFF;
                        if (p != i && p != j && q != i && q != j) {
                            found = 1;
                            break;
                        }
                        break; // same xor already stored, no need to insert again
                    }
                    h = (h + 1) % SZ;
                }
                if (!found && key[h] == 0) {
                    key[h] = x;
                    val[h] = (i << 16) | j;
                }
            }
        }
        printf(found ? "Yes\n" : "No\n");
        free(A);
        free(key);
        free(val);
    }
    return 0;
}

