import sys

def solve_one(n, arr):
    if n > 130:
        return "Yes"
    seen = {}
    for i in range(n):
        ai = arr[i]
        for j in range(i + 1, n):
            x = ai ^ arr[j]
            if x in seen:
                p, q = seen[x]
                if p != i and p != j and q != i and q != j:
                    return "Yes"
            else:
                seen[x] = (i, j)
    return "No"

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it))
        arr = [int(next(it)) for _ in range(n)]
        out_lines.append(solve_one(n, arr))
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
